export const ALL_QUESTIONS: UnifiedQuestion[] = [
  // === MODUL 1 ===
  { id: "m1-q1", moduleId: 1, question: "Was versteht man unter dem Begriff 'Immobilie'?", options: ["Nur Grundstücke ohne Bebauung", "Unbewegliche Sachen, insbesondere Grundstücke und Gebäude", "Nur Wohngebäude", "Ausschließlich gewerblich genutzte Objekte"], correctAnswer: 1, explanation: "Immobilien sind unbewegliche Sachen im Sinne des BGB. Dazu gehören Grundstücke sowie alle fest mit dem Grund und Boden verbundenen Gebäude und Bauwerke. Der Begriff umfasst sowohl Wohn- als auch Gewerbeimmobilien.", category: "Grundlagen", difficulty: "easy" },
  { id: "m1-q2", moduleId: 1, question: "Welche Immobilientypen gibt es NICHT?", options: ["Wohnimmobilien", "Gewerbeimmobilien", "Spezialimmobilien", "Virtuelle Immobilien"], correctAnswer: 3, explanation: "Die klassische Einteilung umfasst Wohnimmobilien (z.B. Einfamilienhäuser, Wohnungen), Gewerbeimmobilien (z.B. Büros, Einzelhandel) und Spezialimmobilien (z.B. Hotels, Pflegeheime). 'Virtuelle Immobilien' ist kein anerkannter Immobilientyp im klassischen Sinne.", category: "Grundlagen", difficulty: "easy" },
  { id: "m1-q3", moduleId: 1, question: "Was ist der Unterschied zwischen Grundstück und Gebäude?", options: ["Es gibt keinen Unterschied", "Grundstück ist der Boden, Gebäude ist die Bebauung", "Grundstück ist größer als Gebäude", "Gebäude ist immer teurer als Grundstück"], correctAnswer: 1, explanation: "Ein Grundstück ist ein abgegrenzter Teil der Erdoberfläche, der im Grundbuch eingetragen ist. Ein Gebäude ist ein Bauwerk, das fest mit dem Grundstück verbunden ist. Nach § 94 BGB sind Gebäude wesentliche Bestandteile des Grundstücks.", category: "Grundlagen", difficulty: "medium" },
  { id: "m1-q4", moduleId: 1, question: "Welche Akteure sind NICHT typischerweise am Immobilienmarkt beteiligt?", options: ["Makler, Verwalter, Gutachter", "Käufer, Verkäufer, Mieter", "Banken, Notare, Bauträger", "Einzelhändler, Gastronomen, Friseure"], correctAnswer: 3, explanation: "Am Immobilienmarkt sind typischerweise Makler, Verwalter, Gutachter, Käufer, Verkäufer, Mieter, Vermieter, Banken, Notare und Bauträger beteiligt. Einzelhändler, Gastronomen und Friseure sind zwar möglicherweise Mieter von Gewerbeimmobilien, aber keine typischen Marktakteure im engeren Sinne.", category: "Marktakteure", difficulty: "easy" },
  { id: "m1-q5", moduleId: 1, question: "Was regelt das Grundbuch?", options: ["Die Bauvorschriften für Immobilien", "Die Eigentumsverhältnisse an Grundstücken", "Die Mietpreise in Deutschland", "Die Steuersätze für Immobilien"], correctAnswer: 1, explanation: "Das Grundbuch ist ein öffentliches Register, das beim Amtsgericht geführt wird. Es dokumentiert die Eigentumsverhältnisse an Grundstücken sowie darauf lastende Rechte (z.B. Grundschulden, Wegerechte). Das Grundbuch genießt öffentlichen Glauben (§ 892 BGB).", category: "Recht", difficulty: "medium" },
  { id: "m1-q6", moduleId: 1, question: "Welche Aussage über den Immobilienmarkt ist FALSCH?", options: ["Der Immobilienmarkt ist regional sehr unterschiedlich", "Lage ist ein entscheidender Wertfaktor", "Alle Immobilien haben denselben Wert pro Quadratmeter", "Angebot und Nachfrage beeinflussen die Preise"], correctAnswer: 2, explanation: "Der Immobilienmarkt ist stark heterogen und regional unterschiedlich. Die Lage ('Lage, Lage, Lage') ist der wichtigste Wertfaktor. Immobilien haben sehr unterschiedliche Quadratmeterpreise je nach Lage, Zustand, Ausstattung und Marktlage. Die Aussage 'Alle Immobilien haben denselben Wert pro m²' ist daher falsch.", category: "Markt", difficulty: "easy" },
  { id: "m1-q7", moduleId: 1, question: "Was bedeutet 'Verkehrswert' einer Immobilie?", options: ["Der Wert der Verkehrsanbindung", "Der Preis, den ein Käufer tatsächlich zahlt", "Der Marktwert, der im gewöhnlichen Geschäftsverkehr erzielbar ist", "Der Wert der Parkplätze"], correctAnswer: 2, explanation: "Der Verkehrswert (auch Marktwert) ist der Preis, der zum Wertermittlungsstichtag im gewöhnlichen Geschäftsverkehr nach den rechtlichen Gegebenheiten und tatsächlichen Eigenschaften erzielbar wäre. Er wird nach § 194 BauGB durch Gutachter ermittelt.", category: "Bewertung", difficulty: "medium" },
  { id: "m1-q8", moduleId: 1, question: "Welche Rechtsform kann KEINE Immobilien besitzen?", options: ["Natürliche Personen", "GmbH", "Vereine", "Alle genannten können Immobilien besitzen"], correctAnswer: 3, explanation: "Alle genannten Rechtsformen können Immobilien besitzen: Natürliche Personen (Privatpersonen), juristische Personen des Privatrechts (GmbH, AG) und juristische Personen des öffentlichen Rechts (Vereine, Stiftungen). Die Eigentumsfähigkeit ist im BGB geregelt.", category: "Recht", difficulty: "medium" },
  { id: "m1-q9", moduleId: 1, question: "Was ist eine 'Teilungserklärung'?", options: ["Die Aufteilung der Maklercourtage", "Die notarielle Erklärung zur Aufteilung eines Grundstücks in Wohnungseigentum", "Die Trennung von Ehepartnern", "Die Aufteilung von Betriebskosten"], correctAnswer: 1, explanation: "Die Teilungserklärung ist eine notariell beurkundete Erklärung des Eigentümers, durch die ein Grundstück in Miteigentumsanteile aufgeteilt wird, die mit Sondereigentum an Wohnungen oder Räumen verbunden sind. Sie ist die Grundlage für Wohnungseigentum.", category: "Recht", difficulty: "hard" },
  { id: "m1-q10", moduleId: 1, question: "Welche Aussage über Grundsteuern ist korrekt?", options: ["Grundsteuer wird nur beim Kauf fällig", "Grundsteuer ist eine jährliche Steuer auf Grundbesitz", "Grundsteuer zahlt nur der Mieter", "Grundsteuer gibt es in Deutschland nicht"], correctAnswer: 1, explanation: "Die Grundsteuer ist eine jährliche Steuer auf den Grundbesitz (Grundstücke und Gebäude). Sie wird von den Gemeinden erhoben und ist vom Eigentümer zu zahlen. Sie kann als Betriebskosten auf Mieter umgelegt werden. Nicht zu verwechseln mit der Grunderwerbsteuer beim Kauf.", category: "Steuern", difficulty: "medium" },
  { id: "m1-extra-11", moduleId: 1, question: "Was ist der Hauptzweck des Maklervertrags?", options: ["Der Makler verpflichtet sich, eine Immobilie zu kaufen.", "Der Makler verpflichtet sich, den Nachweis oder die Vermittlung eines Vertrages zu erbringen.", "Der Makler garantiert den Verkaufserfolg.", "Der Makler wird Eigentümer der Immobilie."], correctAnswer: 1, explanation: "Der Maklervertrag verpflichtet den Makler zum Nachweis der Gelegenheit zum Abschluss eines Vertrages oder zur Vermittlung eines solchen (§ 652 BGB).", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m1-extra-12", moduleId: 1, question: "Welche Formvorschrift gilt für den Maklervertrag über Wohnraum?", options: ["Mündliche Vereinbarung reicht aus.", "Er muss notariell beurkundet werden.", "Er bedarf der Textform (§ 656a BGB).", "Er muss handschriftlich verfasst sein."], correctAnswer: 2, explanation: "Seit dem 23.12.2020 bedarf ein Maklervertrag, der den Nachweis der Gelegenheit zum Abschluss eines Kaufvertrags über eine Wohnung oder ein Einfamilienhaus betrifft, der Textform (z.B. E-Mail).", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m1-extra-13", moduleId: 1, question: "Was versteht man unter dem 'Bestellerprinzip' bei der Wohnraummiete?", options: ["Der Mieter zahlt immer die Provision.", "Der Vermieter zahlt immer die Provision.", "Wer den Makler bestellt, bezahlt ihn (§ 2 Abs. 1a WoVermRG).", "Die Provision wird immer geteilt."], correctAnswer: 2, explanation: "Bei der Vermittlung von Wohnraummietverträgen gilt das Bestellerprinzip: Derjenige, der den Makler beauftragt (bestellt), muss die Provision zahlen.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m1-extra-14", moduleId: 1, question: "Was ist ein 'qualifizierter Alleinauftrag'?", options: ["Der Makler darf auch für andere Kunden tätig werden.", "Der Auftraggeber verzichtet darauf, andere Makler einzuschalten und darf auch nicht selbst tätig werden (umstritten, meist Individualvereinbarung nötig).", "Der Auftraggeber darf parallel andere Makler beauftragen.", "Der Makler erhält eine Festvergütung ohne Erfolg."], correctAnswer: 1, explanation: "Beim qualifizierten Alleinauftrag verpflichtet sich der Auftraggeber, keine anderen Makler einzuschalten und Interessenten an den alleinbeauftragten Makler zu verweisen.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m1-extra-15", moduleId: 1, question: "Wann entsteht der Provisionsanspruch des Maklers?", options: ["Mit Unterzeichnung des Maklervertrags.", "Mit der Besichtigung der Immobilie.", "Mit dem wirksamen Zustandekommen des Hauptvertrags (Kauf- oder Mietvertrag).", "Mit der Reservierung der Immobilie."], correctAnswer: 2, explanation: "Der Provisionsanspruch entsteht erst, wenn der Hauptvertrag (z.B. Kaufvertrag) infolge des Nachweises oder der Vermittlung des Maklers wirksam zustande gekommen ist (§ 652 BGB).", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m1-extra-16", moduleId: 1, question: "Was ist das Grundbuch?", options: ["Ein Verzeichnis aller Einwohner einer Stadt.", "Ein öffentliches Register, das die Rechtsverhältnisse an Grundstücken darlegt.", "Ein Buch über die Bodenbeschaffenheit.", "Eine Liste aller Makler in Deutschland."], correctAnswer: 1, explanation: "Das Grundbuch ist ein öffentliches Register, welches die Eigentumsverhältnisse sowie etwaige Rechte und Lasten an Grundstücken verzeichnet.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m1-extra-17", moduleId: 1, question: "In welcher Abteilung des Grundbuchs stehen Hypotheken und Grundschulden?", options: ["Abteilung I", "Abteilung II", "Abteilung III", "Im Bestandsverzeichnis"], correctAnswer: 2, explanation: "Abteilung III des Grundbuchs enthält die Grundpfandrechte, also Hypotheken, Grundschulden und Rentenschulden.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m1-extra-18", moduleId: 1, question: "Was ist eine 'Auflassung'?", options: ["Die Kündigung eines Mietvertrags.", "Die dingliche Einigung über den Eigentumsübergang an einem Grundstück (§ 925 BGB).", "Die Übergabe der Schlüssel.", "Die Löschung einer Grundschuld."], correctAnswer: 1, explanation: "Die Auflassung ist die zur Übertragung des Eigentums an einem Grundstück erforderliche Einigung zwischen Veräußerer und Erwerber. Sie muss bei gleichzeitiger Anwesenheit beider Teile vor einer zuständigen Stelle (Notar) erklärt werden.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m1-extra-19", moduleId: 1, question: "Was regelt der Flächennutzungsplan (FNP)?", options: ["Die genaue Farbe der Dachziegel.", "Die Art der baulichen Nutzung für das gesamte Gemeindegebiet in Grundzügen.", "Die Bepflanzung der Vorgärten.", "Die Innenraumgestaltung von Gebäuden."], correctAnswer: 1, explanation: "Der Flächennutzungsplan ist der vorbereitende Bauleitplan, der die beabsichtigte Art der Bodennutzung für das gesamte Gemeindegebiet in den Grundzügen darstellt.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m1-extra-20", moduleId: 1, question: "Was bedeutet 'Geschossflächenzahl' (GFZ)?", options: ["Die Anzahl der Fenster pro Geschoss.", "Das Verhältnis der gesamten Geschossfläche zur Größe des Baugrundstücks.", "Die Höhe des Gebäudes in Metern.", "Die Anzahl der erlaubten Stockwerke."], correctAnswer: 1, explanation: "Die Geschossflächenzahl (GFZ) gibt an, wie viel Quadratmeter Geschossfläche je Quadratmeter Grundstücksfläche zulässig sind.", category: "Fachkenntnisse", difficulty: "medium" },
  // === MODUL 2 ===
  { id: "m2-q1", moduleId: 2, question: "Was regelt § 34c GewO?", options: ["Die Mietpreisbremse", "Die Erlaubnispflicht für Immobilienmakler und Darlehensvermittler", "Die Grunderwerbsteuer", "Das Wohnungseigentumsgesetz"], correctAnswer: 1, explanation: "§ 34c GewO regelt die Erlaubnispflicht für die gewerbsmäßige Ausübung der Tätigkeiten als Immobilienmakler, Darlehensvermittler, Bauträger und Baubetreuer. Wer diese Tätigkeiten ausüben möchte, benötigt eine behördliche Erlaubnis.", category: "Maklerrecht", difficulty: "easy" },
  { id: "m2-q2", moduleId: 2, question: "Seit wann gilt das Bestellerprinzip für Wohnungsmakler?", options: ["2015", "2018", "2020", "2022"], correctAnswer: 2, explanation: "Das Bestellerprinzip für Wohnungsmakler gilt seit dem 23. Dezember 2020. Es besagt, dass derjenige, der den Makler beauftragt (bestellt), auch die Provision zahlen muss. Bei Vermietung zahlt der Vermieter, bei Verkauf teilen sich Käufer und Verkäufer die Provision mindestens hälftig.", category: "Maklerrecht", difficulty: "medium" },
  { id: "m2-q3", moduleId: 2, question: "Wie hoch ist die übliche Maklercourtage beim Immobilienkauf?", options: ["1-2% des Kaufpreises", "3,57% bis 7,14% des Kaufpreises (je nach Bundesland)", "10% des Kaufpreises", "Festbetrag von 5.000 €"], correctAnswer: 1, explanation: "Die Maklercourtage beim Immobilienkauf beträgt üblicherweise zwischen 3,57% und 7,14% des Kaufpreises (inkl. MwSt.), abhängig vom Bundesland. Seit 2020 muss der Käufer maximal 50% der Gesamtprovision zahlen, wenn der Verkäufer den Makler beauftragt hat.", category: "Courtage", difficulty: "medium" },
  { id: "m2-q4", moduleId: 2, question: "Wann entsteht der Provisionsanspruch des Maklers?", options: ["Bei Vertragsunterzeichnung", "Bei Besichtigung der Immobilie", "Beim Nachweis oder bei der Vermittlung eines Vertrages", "Nach Ablauf der Widerrufsfrist"], correctAnswer: 2, explanation: "Der Provisionsanspruch des Maklers entsteht, wenn durch seine Tätigkeit ein Vertrag (Kauf, Miete) zustande kommt (Vermittlung) oder er den Vertragspartner nachweist (Nachweis). Der Vertrag muss rechtswirksam sein und nicht mehr widerrufen werden können.", category: "Maklerrecht", difficulty: "medium" },
  { id: "m2-q5", moduleId: 2, question: "Was ist ein 'Alleinauftrag' beim Makler?", options: ["Der Makler darf nur eine Immobilie vermitteln", "Der Eigentümer beauftragt nur einen Makler und schaltet keine weiteren ein", "Der Makler arbeitet allein ohne Team", "Der Auftrag ist auf einen Monat begrenzt"], correctAnswer: 1, explanation: "Bei einem Alleinauftrag verpflichtet sich der Eigentümer, für einen bestimmten Zeitraum nur einen Makler mit der Vermarktung zu beauftragen und keine weiteren Makler einzuschalten. Im Gegenzug verpflichtet sich der Makler zu intensiveren Vermarktungsmaßnahmen.", category: "Maklervertrag", difficulty: "medium" },
  { id: "m2-q6", moduleId: 2, question: "Welche Pflichten hat ein Makler gegenüber seinen Auftraggebern?", options: ["Nur die Immobilie zu zeigen", "Sorgfaltspflicht, Treuepflicht, Aufklärungspflicht", "Nur die Provision einzufordern", "Keine besonderen Pflichten"], correctAnswer: 1, explanation: "Der Makler hat umfassende Pflichten: Sorgfaltspflicht (gewissenhafte Arbeit), Treuepflicht (Interessenwahrung), Aufklärungspflicht (über wesentliche Umstände), Verschwiegenheitspflicht und Rechenschaftspflicht. Verstöße können zu Schadensersatz und Provisionsverlust führen.", category: "Maklerpflichten", difficulty: "medium" },
  { id: "m2-q7", moduleId: 2, question: "Was ist die 'Makler- und Bauträgerverordnung' (MaBV)?", options: ["Eine Verordnung über Bauvorschriften", "Eine Verordnung über die Pflichten von Maklern und Bauträgern", "Eine Steuerverordnung", "Eine Mietrechtsverordnung"], correctAnswer: 1, explanation: "Die MaBV regelt die Pflichten von Immobilienmaklern, Darlehensvermittlern, Bauträgern und Baubetreuern. Sie enthält Vorschriften über Vermögensschäden-Haftpflichtversicherung, Werbung, Vertragsanbahnung und Informationspflichten.", category: "Maklerrecht", difficulty: "hard" },
  { id: "m2-q8", moduleId: 2, question: "Welche Versicherung muss ein Makler nach MaBV abschließen?", options: ["Krankenversicherung", "Vermögensschaden-Haftpflichtversicherung", "Lebensversicherung", "Rechtsschutzversicherung"], correctAnswer: 1, explanation: "Nach § 3 MaBV muss ein Makler eine Vermögensschaden-Haftpflichtversicherung mit einer Mindestdeckungssumme von 500.000 € für Personenschäden und 250.000 € für sonstige Schäden abschließen. Dies dient dem Schutz der Auftraggeber.", category: "Versicherung", difficulty: "medium" },
  { id: "m2-q9", moduleId: 2, question: "Was bedeutet 'qualifizierter Alleinauftrag'?", options: ["Der Makler hat eine besondere Qualifikation", "Der Eigentümer darf selbst nicht mehr verkaufen", "Der Eigentümer beauftragt nur einen Makler, darf aber selbst noch verkaufen", "Der Auftrag ist besonders teuer"], correctAnswer: 2, explanation: "Beim qualifizierten Alleinauftrag beauftragt der Eigentümer nur einen Makler, behält sich aber das Recht vor, die Immobilie selbst zu verkaufen. Beim einfachen Alleinauftrag ist auch der Eigenverkauf ausgeschlossen. Der qualifizierte Alleinauftrag ist die häufigste Form.", category: "Maklervertrag", difficulty: "hard" },
  { id: "m2-q10", moduleId: 2, question: "Welche Angaben MÜSSEN in einem Immobilienexposé enthalten sein?", options: ["Nur der Preis", "Energieausweis-Angaben sind Pflicht", "Nur die Adresse", "Keine Pflichtangaben"], correctAnswer: 1, explanation: "Nach EnEV/GEG müssen in kommerziellen Immobilienanzeigen bestimmte Energieausweis-Angaben gemacht werden: Art des Ausweises, Energieträger, Baujahr, Energieeffizienzklasse und Energiekennwert. Verstöße können mit Bußgeldern geahndet werden.", category: "Exposé", difficulty: "hard" },
  { id: "m2-extra-11", moduleId: 2, question: "Welche Erlaubnis ist für die Tätigkeit als Immobilienmakler zwingend erforderlich?", options: ["Gewerbeanmeldung nach §14 GewO", "Erlaubnis nach §34c GewO", "Handelsregistereintrag", "IHK-Zertifikat"], correctAnswer: 1, explanation: "Die Tätigkeit als Immobilienmakler ist erlaubnispflichtig nach §34c der Gewerbeordnung (GewO). Eine bloße Gewerbeanmeldung reicht nicht aus.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m2-extra-12", moduleId: 2, question: "Was versteht man unter dem 'Bestellerprinzip' bei der Wohnraumvermittlung?", options: ["Der Käufer zahlt immer die Provision.", "Derjenige zahlt den Makler, der ihn schriftlich beauftragt hat.", "Die Provision wird immer 50/50 geteilt.", "Der Verkäufer zahlt immer die Provision."], correctAnswer: 1, explanation: "Seit 2015 gilt bei der Wohnraumvermietung das Bestellerprinzip: Wer bestellt (beauftragt), der bezahlt. Meist ist dies der Vermieter.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m2-extra-13", moduleId: 2, question: "Wie lange beträgt die gesetzliche Widerrufsfrist bei Maklerverträgen, die im Fernabsatz geschlossen wurden?", options: ["14 Tage", "1 Monat", "7 Tage", "Es gibt kein Widerrufsrecht"], correctAnswer: 0, explanation: "Verbraucher haben bei Fernabsatzverträgen (z.B. per E-Mail oder Telefon) ein gesetzliches Widerrufsrecht von 14 Tagen.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m2-extra-14", moduleId: 2, question: "Welche Pflichten hat ein Makler nach dem Geldwäschegesetz (GwG)?", options: ["Nur Bargeld annehmen", "Identifizierung des Vertragspartners und Risikobewertung", "Meldung aller Verkäufe an das Finanzamt", "Keine besonderen Pflichten"], correctAnswer: 1, explanation: "Immobilienmakler sind Verpflichtete nach dem GwG und müssen ihre Vertragspartner identifizieren (KYC) sowie eine Risikoanalyse durchführen.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m2-extra-15", moduleId: 2, question: "Was ist ein 'qualifizierter Alleinauftrag'?", options: ["Ein Auftrag, bei dem der Makler keine Provision erhält.", "Ein Auftrag, bei dem der Kunde auch andere Makler beauftragen darf.", "Ein Auftrag, der den Kunden verpflichtet, nicht selbst tätig zu werden (Interessenten an Makler verweisen).", "Ein Auftrag nur für qualifizierte Immobilien."], correctAnswer: 2, explanation: "Beim qualifizierten Alleinauftrag verzichtet der Auftraggeber darauf, parallel andere Makler einzuschalten UND verpflichtet sich, eigene Interessenten an den Makler zu verweisen.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m2-bgh-1", moduleId: 2, question: "Was entschied der BGH (I ZR 32/24) zum Halbteilungsgrundsatz bei Maklerprovisionen?", options: ["Makler darf unterschiedliche Provisionen vereinbaren", "Bei Doppeltätigkeit müssen Käufer und Verkäufer gleich hohe Provisionen zahlen (§ 656c BGB)", "Halbteilungsgrundsatz gilt nur bei Gewerbeimmobilien", "Dritte wie Ehepartner sind ausgenommen"], correctAnswer: 1, explanation: "BGH I ZR 32/24: § 656c BGB gilt auch wenn der Maklervertrag mit einem Dritten statt der Kaufvertragspartei geschlossen wird. Unterschiedliche Provisionen machen den Vertrag unwirksam.", category: "BGH-Rechtsprechung", difficulty: "hard" },
  { id: "m2-bgh-2", moduleId: 2, question: "Welche Rechtsfolge hat ein Verstoß gegen den Halbteilungsgrundsatz laut BGH?", options: ["Nur der übersteigende Betrag ist unwirksam", "Reduzierung auf gesetzliche Höchstprovision", "Der gesamte Maklervertrag ist unwirksam — kein Provisionsanspruch", "Geldbuße bis 10.000 €"], correctAnswer: 2, explanation: "BGH I ZR 32/24: Bei Verstoß gegen § 656c BGB ist der gesamte Maklervertrag unwirksam. Der Makler verliert vollständig seinen Provisionsanspruch.", category: "BGH-Rechtsprechung", difficulty: "hard" },
  // === MODUL 3 ===
  { id: "m3-q1", moduleId: 3, question: "Was bedeutet 'WEG'?", options: ["Wohnungseigentumsgesetz", "Wohnungseigentümergemeinschaft", "Wohnungserwerbs-Gesetz", "Wohnungs-Entwicklungs-Gesellschaft"], correctAnswer: 0, explanation: "WEG steht für 'Wohnungseigentumsgesetz'. Es regelt das Wohnungseigentum und die Rechte und Pflichten der Wohnungseigentümer. Umgangssprachlich wird auch die Wohnungseigentümergemeinschaft als 'WEG' bezeichnet.", category: "WEG-Verwaltung", difficulty: "easy" },
  { id: "m3-q2", moduleId: 3, question: "Was ist das 'Sondereigentum' in einer WEG?", options: ["Das Eigentum an der gesamten Immobilie", "Das ausschließliche Eigentum an einer Wohnung oder Räumen", "Das Eigentum am Grundstück", "Das Eigentum an Gemeinschaftsanlagen"], correctAnswer: 1, explanation: "Sondereigentum ist das ausschließliche Eigentum an einer Wohnung oder an nicht zu Wohnzwecken dienenden Räumen (Teileigentum). Es ist mit einem Miteigentumsanteil am Gemeinschaftseigentum verbunden. Der Eigentümer kann über sein Sondereigentum frei verfügen.", category: "WEG-Verwaltung", difficulty: "medium" },
  { id: "m3-q3", moduleId: 3, question: "Was gehört zum 'Gemeinschaftseigentum' in einer WEG?", options: ["Nur das Grundstück", "Nur das Treppenhaus", "Grundstück, tragende Wände, Dach, Fassade, Treppenhaus, Heizung", "Nur die Wohnungen"], correctAnswer: 2, explanation: "Zum Gemeinschaftseigentum gehören alle Teile des Grundstücks und Gebäudes, die nicht Sondereigentum sind: Grundstück, tragende Wände, Dach, Fassade, Treppenhaus, Aufzug, Heizungsanlage, Leitungen (außerhalb der Wohnung). Alle Eigentümer sind daran gemeinschaftlich berechtigt.", category: "WEG-Verwaltung", difficulty: "medium" },
  { id: "m3-q4", moduleId: 3, question: "Was ist eine 'Eigentümerversammlung'?", options: ["Ein geselliges Treffen der Eigentümer", "Das beschlussfassende Organ der Wohnungseigentümergemeinschaft", "Eine Versammlung von Mietern", "Ein Treffen mit dem Verwalter"], correctAnswer: 1, explanation: "Die Eigentümerversammlung ist das oberste Beschlussorgan der WEG. Hier treffen sich alle Wohnungseigentümer, um über wichtige Angelegenheiten zu entscheiden (z.B. Jahresabrechnung, Instandhaltungsmaßnahmen, Verwalterwahl). Beschlüsse werden nach Köpfen oder Miteigentumsanteilen gefasst.", category: "WEG-Verwaltung", difficulty: "medium" },
  { id: "m3-q5", moduleId: 3, question: "Was ist die 'Instandhaltungsrücklage'?", options: ["Eine Rücklage für Notfälle", "Eine Rücklage für zukünftige Instandhaltungs- und Instandsetzungsmaßnahmen", "Eine Rücklage für Versicherungen", "Eine Rücklage für Steuern"], correctAnswer: 1, explanation: "Die Instandhaltungsrücklage ist eine finanzielle Rücklage der WEG für zukünftige Instandhaltungs- und Instandsetzungsmaßnahmen am Gemeinschaftseigentum (z.B. Dachsanierung, Fassadenanstrich). Jeder Eigentümer zahlt monatlich einen Betrag ein, der nach Miteigentumsanteilen berechnet wird.", category: "WEG-Verwaltung", difficulty: "medium" },
  { id: "m3-q6", moduleId: 3, question: "Was sind 'Betriebskosten' im Mietrecht?", options: ["Die Kosten für den Betrieb eines Unternehmens", "Die Kosten, die dem Eigentümer durch den Betrieb der Immobilie entstehen", "Die Kosten für Reparaturen", "Die Kosten für Möbel"], correctAnswer: 1, explanation: "Betriebskosten sind die Kosten, die dem Eigentümer durch den bestimmungsgemäßen Gebrauch der Immobilie laufend entstehen. Dazu gehören z.B. Grundsteuer, Wasser, Heizung, Müllabfuhr, Hausmeister. Sie können auf den Mieter umgelegt werden, wenn dies im Mietvertrag vereinbart ist.", category: "Mietverwaltung", difficulty: "medium" },
  { id: "m3-q7", moduleId: 3, question: "Welche Kosten dürfen NICHT als Betriebskosten auf Mieter umgelegt werden?", options: ["Grundsteuer", "Wasserkosten", "Verwaltungskosten", "Heizkosten"], correctAnswer: 2, explanation: "Verwaltungskosten (z.B. Kosten für Hausverwaltung, Bankgebühren, Porto) dürfen nicht als Betriebskosten auf Mieter umgelegt werden. Sie sind Kosten des Eigentümers. Umlagefähig sind nur die in § 2 BetrKV aufgeführten Kostenarten.", category: "Betriebskosten", difficulty: "hard" },
  { id: "m3-q8", moduleId: 3, question: "Was ist eine 'Nebenkostenabrechnung'?", options: ["Eine Rechnung für Reparaturen", "Die jährliche Abrechnung der umlagefähigen Betriebskosten", "Eine Rechnung für Möbel", "Die Mietrechnung"], correctAnswer: 1, explanation: "Die Nebenkostenabrechnung (auch Betriebskostenabrechnung) ist die jährliche Abrechnung der auf den Mieter umgelegten Betriebskosten. Der Vermieter muss sie spätestens 12 Monate nach Ende des Abrechnungszeitraums erstellen. Der Mieter hat ein Recht auf Einsicht in die Belege.", category: "Betriebskosten", difficulty: "medium" },
  { id: "m3-q9", moduleId: 3, question: "Was ist der Unterschied zwischen 'Instandhaltung' und 'Instandsetzung'?", options: ["Es gibt keinen Unterschied", "Instandhaltung = vorbeugende Maßnahmen, Instandsetzung = Reparatur von Schäden", "Instandsetzung ist teurer", "Instandhaltung ist nur für Mieter"], correctAnswer: 1, explanation: "Instandhaltung umfasst vorbeugende Maßnahmen zur Erhaltung des ordnungsgemäßen Zustands (z.B. Wartung, Pflege). Instandsetzung bedeutet die Beseitigung von Schäden und Mängeln (z.B. Reparatur defekter Teile). Beide Begriffe sind wichtig für die Kostenabgrenzung in WEG und Mietverwaltung.", category: "Instandhaltung", difficulty: "hard" },
  { id: "m3-q10", moduleId: 3, question: "Wie wird das 'Hausgeld' in einer WEG berechnet?", options: ["Alle Eigentümer zahlen denselben Betrag", "Nach Miteigentumsanteilen (MEA)", "Nach Wohnungsgröße", "Nach Anzahl der Personen"], correctAnswer: 1, explanation: "Das Hausgeld wird nach Miteigentumsanteilen (MEA) berechnet. Jeder Eigentümer zahlt entsprechend seinem Anteil am Gemeinschaftseigentum. Das Hausgeld umfasst Betriebskosten, Verwaltungskosten und die Zuführung zur Instandhaltungsrücklage.", category: "Hausgeld", difficulty: "medium" },
  { id: "m3-extra-11", moduleId: 3, question: "Was ist die Hauptaufgabe eines WEG-Verwalters?", options: ["Vermietung der Wohnungen", "Verwaltung des gemeinschaftlichen Eigentums", "Verkauf der Wohnungen", "Renovierung des Sondereigentums"], correctAnswer: 1, explanation: "Der WEG-Verwalter ist primär für die Verwaltung des gemeinschaftlichen Eigentums (Dach, Fassade, Treppenhaus etc.) zuständig, nicht für das Sondereigentum.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m3-extra-12", moduleId: 3, question: "Welches Gesetz wurde 2020 umfassend reformiert und betrifft die Wohnungseigentumsverwaltung?", options: ["BGB", "WEMoG (Wohnungseigentumsmodernisierungsgesetz)", "GewO", "BauGB"], correctAnswer: 1, explanation: "Das WEMoG trat am 01.12.2020 in Kraft und hat das WEG-Recht grundlegend reformiert (z.B. Zertifizierter Verwalter, bauliche Veränderungen).", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m3-extra-13", moduleId: 3, question: "Wann muss die Eigentümerversammlung (ETV) mindestens einberufen werden?", options: ["Alle 2 Jahre", "Mindestens einmal im Jahr", "Nur bei Bedarf", "Alle 6 Monate"], correctAnswer: 1, explanation: "Nach § 24 Abs. 1 WEG muss der Verwalter die Eigentümerversammlung mindestens einmal im Jahr einberufen.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m3-extra-14", moduleId: 3, question: "Was ist die 'Erhaltungsrücklage' (früher Instandhaltungsrücklage)?", options: ["Der Gewinn des Verwalters", "Eine Ansammlung von Mitteln für künftige Instandsetzungen am Gemeinschaftseigentum", "Die Kaution der Mieter", "Eine Steuer für Eigentümer"], correctAnswer: 1, explanation: "Die Erhaltungsrücklage ist eine zweckgebundene Rücklage der Eigentümergemeinschaft, um zukünftige Reparaturen und Sanierungen am Gemeinschaftseigentum zu finanzieren.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m3-extra-15", moduleId: 3, question: "Wer bestellt den Verwalter in einer WEG?", options: ["Das Amtsgericht", "Die Eigentümerversammlung durch Beschluss", "Der Verwaltungsbeirat allein", "Die Gemeinde"], correctAnswer: 1, explanation: "Der Verwalter wird von der Eigentümerversammlung durch Mehrheitsbeschluss bestellt (§ 26 WEG).", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m3-bgh-1", moduleId: 3, question: "Was regelt § 656c BGB zum Schutz von Wohnungskäufern?", options: ["Pflicht zur Energieausweisvorlage", "Bei Doppelbeauftragung darf die Käuferprovision die Verkäuferprovision nicht übersteigen", "Widerruf von Maklerverträgen", "Haftung für Sachmängel"], correctAnswer: 1, explanation: "§ 656c BGB: Wenn der Makler von beiden Seiten beauftragt wird, darf der Käufer nicht mehr zahlen als der Verkäufer (Halbteilungsgrundsatz).", category: "WEG-Rechtsprechung", difficulty: "medium" },
  { id: "m3-bgh-2", moduleId: 3, question: "Innerhalb welcher Frist muss eine WEG-Beschlussanfechtungsklage erhoben werden?", options: ["6 Monate", "3 Monate", "1 Monat nach Beschlussfassung", "2 Wochen"], correctAnswer: 2, explanation: "§ 44 WEG: Anfechtungsklage muss innerhalb eines Monats nach Beschlussfassung erhoben werden.", category: "WEG-Rechtsprechung", difficulty: "hard" },
  // === MODUL 4 ===
  { id: "m4-q1", moduleId: 4, question: "Was ist der 'Verkehrswert' einer Immobilie?", options: ["Der Wert der Verkehrsanbindung", "Der Marktwert, der im gewöhnlichen Geschäftsverkehr erzielbar ist", "Der Versicherungswert", "Der Beleihungswert"], correctAnswer: 1, explanation: "Der Verkehrswert (auch Marktwert) ist der Preis, der zum Wertermittlungsstichtag im gewöhnlichen Geschäftsverkehr nach den rechtlichen Gegebenheiten und tatsächlichen Eigenschaften ohne Rücksicht auf ungewöhnliche oder persönliche Verhältnisse erzielbar wäre.", category: "Bewertung", difficulty: "medium" },
  { id: "m4-q2", moduleId: 4, question: "Welche Wertermittlungsverfahren gibt es?", options: ["Nur das Vergleichswertverfahren", "Vergleichswertverfahren, Ertragswertverfahren, Sachwertverfahren", "Nur das Ertragswertverfahren", "Nur das Sachwertverfahren"], correctAnswer: 1, explanation: "Es gibt drei normierte Wertermittlungsverfahren: Vergleichswertverfahren (Vergleich mit ähnlichen Objekten), Ertragswertverfahren (kapitalisierte Erträge) und Sachwertverfahren (Herstellungskosten minus Alterswertminderung). Die Wahl hängt von der Immobilienart ab.", category: "Bewertung", difficulty: "medium" },
  { id: "m4-q3", moduleId: 4, question: "Für welche Immobilienart ist das Ertragswertverfahren geeignet?", options: ["Eigengenutzte Einfamilienhäuser", "Vermietete Mehrfamilienhäuser und Gewerbeimmobilien", "Unbebaute Grundstücke", "Denkmalgeschützte Gebäude"], correctAnswer: 1, explanation: "Das Ertragswertverfahren wird für vermietete Immobilien angewendet, bei denen der Ertrag (Miete) im Vordergrund steht. Es eignet sich für Mehrfamilienhäuser, Gewerbeimmobilien und gemischt genutzte Objekte. Der Wert ergibt sich aus den kapitalisierten Reinerträgen.", category: "Ertragswertverfahren", difficulty: "medium" },
  { id: "m4-q4", moduleId: 4, question: "Was ist der 'Bodenwert'?", options: ["Der Wert des Bodenbelags", "Der Wert des unbebauten Grundstücks", "Der Wert des Kellers", "Der Wert der Gartenanlage"], correctAnswer: 1, explanation: "Der Bodenwert ist der Wert des unbebauten Grundstücks. Er wird im Vergleichswertverfahren anhand von Bodenrichtwerten ermittelt. Der Bodenwert ist eine wichtige Größe im Sachwertverfahren und Ertragswertverfahren.", category: "Bewertung", difficulty: "easy" },
  { id: "m4-q5", moduleId: 4, question: "Was sind 'Bodenrichtwerte'?", options: ["Durchschnittliche Ladenpreise für Grundstücke in einer Lage", "Vorschriften für die Bodenbeschaffenheit", "Werte für die Bodenqualität", "Steuerwerte für Grundstücke"], correctAnswer: 0, explanation: "Bodenrichtwerte sind durchschnittliche Ladenpreise für unbebaute Grundstücke in einer bestimmten Lage. Sie werden von Gutachterausschüssen ermittelt und veröffentlicht. Sie dienen als Orientierung für die Wertermittlung und werden nach Lage, Art und Maß der Nutzung differenziert.", category: "Bodenwert", difficulty: "medium" },
  { id: "m4-q6", moduleId: 4, question: "Was ist die 'Alterswertminderung'?", options: ["Die Minderung des Werts durch das Alter des Eigentümers", "Die Minderung des Gebäudewerts durch Alterung und Abnutzung", "Die Minderung der Miete bei alten Gebäuden", "Die Minderung der Grundsteuer"], correctAnswer: 1, explanation: "Die Alterswertminderung ist die Minderung des Gebäudewerts durch Alterung, Abnutzung und technische Überholung. Sie wird im Sachwertverfahren vom Gebäudesachwert abgezogen. Die Berechnung erfolgt linear über die Gesamtnutzungsdauer des Gebäudes.", category: "Sachwertverfahren", difficulty: "medium" },
  { id: "m4-q7", moduleId: 4, question: "Was ist ein 'Verkehrswertgutachten'?", options: ["Ein Gutachten über die Verkehrsanbindung", "Ein Gutachten zur Ermittlung des Marktwerts einer Immobilie", "Ein Gutachten über Verkehrsunfälle", "Ein Gutachten über Parkplätze"], correctAnswer: 1, explanation: "Ein Verkehrswertgutachten ist ein Gutachten zur Ermittlung des Marktwerts (Verkehrswerts) einer Immobilie. Es wird von Sachverständigen nach normierten Verfahren erstellt und dient z.B. für Erbauseinandersetzungen, Scheidungen, Zwangsversteigerungen oder Kreditvergaben.", category: "Gutachten", difficulty: "easy" },
  { id: "m4-q8", moduleId: 4, question: "Wer darf Verkehrswertgutachten erstellen?", options: ["Nur Notare", "Nur öffentlich bestellte und vereidigte Sachverständige", "Jeder, aber für Gerichte nur zertifizierte Sachverständige", "Nur Makler"], correctAnswer: 2, explanation: "Grundsätzlich darf jeder Verkehrswertgutachten erstellen. Für gerichtliche Zwecke werden jedoch meist öffentlich bestellte und vereidigte Sachverständige oder zertifizierte Sachverständige (z.B. nach DIN EN ISO/IEC 17024) beauftragt. Banken akzeptieren oft nur Gutachten von anerkannten Sachverständigen.", category: "Sachverständige", difficulty: "hard" },
  { id: "m4-q9", moduleId: 4, question: "Was ist der Unterschied zwischen 'Verkehrswert' und 'Beleihungswert'?", options: ["Es gibt keinen Unterschied", "Verkehrswert = Marktwert, Beleihungswert = vorsichtig geschätzter Wert für Kreditsicherheit", "Beleihungswert ist immer höher", "Verkehrswert ist nur für Verkäufe relevant"], correctAnswer: 1, explanation: "Der Verkehrswert ist der Marktwert, der im normalen Geschäftsverkehr erzielbar ist. Der Beleihungswert ist der Wert, den eine Bank bei der Kreditvergabe als Sicherheit ansetzt. Er liegt meist 10-20% unter dem Verkehrswert, da er vorsichtig und nachhaltig geschätzt wird.", category: "Bewertung", difficulty: "hard" },
  { id: "m4-q10", moduleId: 4, question: "Was ist ein 'Kurzgutachten'?", options: ["Ein Gutachten, das sehr schnell erstellt wird", "Ein vereinfachtes Gutachten mit weniger Detailtiefe", "Ein Gutachten über kurze Gebäude", "Ein Gutachten für kurze Zeiträume"], correctAnswer: 1, explanation: "Ein Kurzgutachten ist ein vereinfachtes Verkehrswertgutachten mit reduziertem Umfang und weniger Detailtiefe. Es enthält die wesentlichen Wertermittlungsdaten, aber weniger Begründungen und Anlagen. Es ist günstiger und schneller zu erstellen als ein Vollgutachten.", category: "Gutachten", difficulty: "medium" },
  { id: "m4-extra-11", moduleId: 4, question: "Welches Verfahren ist für die Bewertung von Ein- und Zweifamilienhäusern primär anzuwenden?", options: ["Ertragswertverfahren", "Sachwertverfahren", "Vergleichswertverfahren", "Discounted-Cash-Flow-Verfahren"], correctAnswer: 1, explanation: "Das Sachwertverfahren wird vorrangig bei Immobilien angewendet, die für die Eigennutzung konzipiert sind, wie Ein- und Zweifamilienhäuser, da hier der Substanzwert im Vordergrund steht.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m4-extra-12", moduleId: 4, question: "Was ist der Bodenrichtwert?", options: ["Der durchschnittliche Lagewert des Bodens für eine Mehrheit von Grundstücken", "Der individuelle Wert eines konkreten Grundstücks", "Der Verkaufspreis des letzten Jahres", "Der Wert des Bodens inklusive Bebauung"], correctAnswer: 0, explanation: "Der Bodenrichtwert ist ein aus Kaufpreissammlungen ermittelter durchschnittlicher Lagewert für eine Mehrheit von Grundstücken innerhalb eines abgegrenzten Gebiets (Bodenrichtwertzone).", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m4-extra-13", moduleId: 4, question: "Was versteht man unter dem Liegenschaftszins?", options: ["Den Zinssatz für Hypothekendarlehen", "Die Verzinsung des Verkehrswertes von Grundstücken", "Den Zinssatz der Europäischen Zentralbank", "Die Renditeerwartung des Mieters"], correctAnswer: 1, explanation: "Der Liegenschaftszins ist der Zinssatz, mit dem der Verkehrswert von Grundstücken marktüblich verzinst wird. Er ist eine wesentliche Größe im Ertragswertverfahren.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m4-extra-14", moduleId: 4, question: "Welche Faktoren beeinflussen den Rohertrag einer Immobilie?", options: ["Nur die Größe des Grundstücks", "Mieteinnahmen, Lage, Zustand und Ausstattung", "Das Alter des Eigentümers", "Die Farbe der Fassade"], correctAnswer: 1, explanation: "Der Rohertrag wird maßgeblich durch die nachhaltig erzielbaren Mieteinnahmen bestimmt, welche wiederum von Lage, Zustand und Ausstattung der Immobilie abhängen.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m4-extra-15", moduleId: 4, question: "Was ist bei der Bewertung von Erbbaurechten besonders zu beachten?", options: ["Es gibt keine Besonderheiten", "Das Erbbaurecht wird wie Volleigentum behandelt", "Die Laufzeit des Erbbaurechts und der Erbbauzins", "Erbbaurechte können nicht bewertet werden"], correctAnswer: 2, explanation: "Bei Erbbaurechten sind die Restlaufzeit des Vertrages und die Höhe des zu zahlenden Erbbauzinses wertbestimmende Faktoren, die den Verkehrswert maßgeblich beeinflussen.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m4-extra-16", moduleId: 4, question: "Welche Aufgabe hat der Gutachterausschuss?", options: ["Erteilung von Baugenehmigungen", "Führung der Kaufpreissammlung und Ermittlung von Bodenrichtwerten", "Vermittlung von Immobilien", "Festsetzung der Grundsteuer"], correctAnswer: 1, explanation: "Der Gutachterausschuss führt die Kaufpreissammlung, wertet diese aus und ermittelt darauf basierend Bodenrichtwerte und sonstige für die Wertermittlung erforderliche Daten.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m4-extra-17", moduleId: 4, question: "Was versteht man unter 'Marktanpassung' im Sachwertverfahren?", options: ["Die Anpassung der Miete an den Mietspiegel", "Die Berücksichtigung der aktuellen Marktlage durch den Sachwertfaktor", "Die Renovierung der Immobilie vor dem Verkauf", "Die Anpassung des Bodenrichtwerts"], correctAnswer: 1, explanation: "Da der vorläufige Sachwert rein rechnerisch ermittelt wird, muss er durch den Sachwertfaktor an die tatsächliche Marktlage angepasst werden, um den Verkehrswert zu erhalten.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m4-extra-18", moduleId: 4, question: "Welches Gesetz regelt die Immobilienwertermittlung in Deutschland maßgeblich?", options: ["BGB", "BauGB und ImmoWertV", "StGB", "HGB"], correctAnswer: 1, explanation: "Das Baugesetzbuch (BauGB) und die Immobilienwertermittlungsverordnung (ImmoWertV) bilden die rechtliche Grundlage für die Verkehrswertermittlung in Deutschland.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m4-extra-19", moduleId: 4, question: "Was ist der Unterschied zwischen Verkehrswert und Beleihungswert?", options: ["Es gibt keinen Unterschied", "Verkehrswert ist der aktuelle Marktwert, Beleihungswert ein vorsichtigerer Wert für Kreditsicherheiten", "Beleihungswert ist immer höher als der Verkehrswert", "Verkehrswert gilt nur für Gewerbeimmobilien"], correctAnswer: 1, explanation: "Der Verkehrswert spiegelt den aktuellen Marktwert wider, während der Beleihungswert ein unter Sicherheitsaspekten ermittelter Wert ist, der langfristig erzielt werden kann und meist unter dem Verkehrswert liegt.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m4-extra-20", moduleId: 4, question: "Was bedeutet 'Restnutzungsdauer'?", options: ["Die Zeit bis zum nächsten Mieterwechsel", "Die Anzahl der Jahre, in denen eine bauliche Anlage bei ordnungsgemäßer Bewirtschaftung voraussichtlich noch wirtschaftlich genutzt werden kann", "Die Dauer der Bauphase", "Die Zeit bis zur vollständigen Abschreibung"], correctAnswer: 1, explanation: "Die Restnutzungsdauer ist die Zeitspanne, in der ein Gebäude voraussichtlich noch wirtschaftlich genutzt werden kann. Sie ist eine zentrale Größe in allen Wertermittlungsverfahren.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m4-bgh-1", moduleId: 4, question: "Was bedeutet \"Nachhaltigkeit\" bei der Verkehrswertermittlung?", options: ["Ökologische Bauweise", "Wertermittlung auf Basis dauerhaft erzielbarer, nicht spekulativer Erträge", "Mindesthaltedauer von 10 Jahren", "Nachhaltiges Investieren"], correctAnswer: 1, explanation: "Bei der Verkehrswertermittlung sind nur nachhaltig erzielbare Preise anzusetzen — konjunkturelle Hochphasen bleiben unberücksichtigt.", category: "Wertermittlung-Rechtsprechung", difficulty: "hard" },
  { id: "m4-bgh-2", moduleId: 4, question: "Wofür sind Gutachterausschüsse nach BauGB zuständig?", options: ["Baugenehmigungen", "Ermittlung von Bodenrichtwerten und Kaufpreissammlungen", "Grundbucheintragungen", "Besteuerung von Immobilientransaktionen"], correctAnswer: 1, explanation: "§§ 192-199 BauGB: Gutachterausschüsse ermitteln Bodenrichtwerte, führen Kaufpreissammlungen und erstellen Marktberichte.", category: "Wertermittlung-Rechtsprechung", difficulty: "medium" },
  // === MODUL 5 ===
  { id: "m5-q1", moduleId: 5, question: "Was regelt § 34i GewO?", options: ["Die Immobilienmakler-Erlaubnis", "Die Erlaubnispflicht für Darlehensvermittler", "Die Grunderwerbsteuer", "Das Mietrecht"], correctAnswer: 1, explanation: "§ 34i GewO regelt die Erlaubnispflicht für Darlehensvermittler, Finanzanlagenvermittler und Honorar-Finanzanlagenberater. Wer gewerbsmäßig Darlehensverträge vermittelt, benötigt eine behördliche Erlaubnis nach § 34i GewO.", category: "Darlehensvermittlung", difficulty: "easy" },
  { id: "m5-q2", moduleId: 5, question: "Was ist ein 'Annuitätendarlehen'?", options: ["Ein Darlehen mit steigenden Raten", "Ein Darlehen mit gleichbleibenden Raten aus Zins und Tilgung", "Ein Darlehen ohne Zinsen", "Ein Darlehen nur für Immobilien"], correctAnswer: 1, explanation: "Ein Annuitätendarlehen ist die häufigste Darlehensform bei Immobilienfinanzierungen. Die monatliche Rate (Annuität) bleibt während der Zinsbindung konstant. Sie setzt sich aus Zins und Tilgung zusammen. Mit jeder Rate sinkt der Zinsanteil und der Tilgungsanteil steigt.", category: "Finanzierung", difficulty: "medium" },
  { id: "m5-q3", moduleId: 5, question: "Was bedeutet 'Zinsbindung'?", options: ["Die Zinsen sind für immer festgelegt", "Der Zinssatz ist für einen vereinbarten Zeitraum fest", "Die Zinsen können jederzeit geändert werden", "Die Zinsen sind an die Inflation gebunden"], correctAnswer: 1, explanation: "Die Zinsbindung ist der Zeitraum, für den der Zinssatz eines Darlehens fest vereinbart ist (z.B. 10, 15 oder 20 Jahre). Während dieser Zeit kann die Bank den Zinssatz nicht ändern. Nach Ablauf der Zinsbindung wird eine Anschlussfinanzierung benötigt.", category: "Finanzierung", difficulty: "medium" },
  { id: "m5-q4", moduleId: 5, question: "Was ist die 'Tilgung' bei einem Darlehen?", options: ["Die Zinszahlung", "Die Rückzahlung des Darlehensbetrags", "Die Gebühren der Bank", "Die Versicherungsprämie"], correctAnswer: 1, explanation: "Die Tilgung ist die Rückzahlung des Darlehensbetrags (Kapital). Bei einem Annuitätendarlehen wird mit jeder Rate ein Teil getilgt. Die Tilgung wird in Prozent pro Jahr angegeben (z.B. 2% Anfangstilgung). Je höher die Tilgung, desto schneller ist das Darlehen abbezahlt.", category: "Finanzierung", difficulty: "easy" },
  { id: "m5-q5", moduleId: 5, question: "Was ist ein 'Tilgungsplan'?", options: ["Ein Plan für die Bauplanung", "Eine Übersicht über die Rückzahlung des Darlehens", "Ein Plan für die Zinszahlungen", "Ein Plan für die Versicherungen"], correctAnswer: 1, explanation: "Ein Tilgungsplan ist eine tabellarische Übersicht über den Verlauf der Darlehensrückzahlung. Er zeigt für jede Rate den Zinsanteil, Tilgungsanteil und die Restschuld. Der Tilgungsplan wird von der Bank bei Vertragsabschluss erstellt und ist wichtig für die Finanzplanung.", category: "Finanzierung", difficulty: "medium" },
  { id: "m5-q6", moduleId: 5, question: "Was ist die 'Grundschuld'?", options: ["Eine Steuer auf Grundstücke", "Ein dingliches Recht zur Absicherung von Darlehen", "Eine Schuld des Grundstücks", "Eine Gebühr für das Grundbuch"], correctAnswer: 1, explanation: "Die Grundschuld ist ein dingliches Recht, das im Grundbuch eingetragen wird. Sie dient der Bank als Sicherheit für ein Darlehen. Im Gegensatz zur Hypothek ist die Grundschuld nicht akzessorisch, d.h. sie bleibt auch nach Tilgung des Darlehens bestehen und kann für weitere Kredite genutzt werden.", category: "Finanzierung", difficulty: "medium" },
  { id: "m5-q7", moduleId: 5, question: "Was ist der 'Beleihungswert' einer Immobilie?", options: ["Der Verkehrswert", "Der Wert, den eine Bank als Sicherheit für ein Darlehen ansetzt", "Der Versicherungswert", "Der Kaufpreis"], correctAnswer: 1, explanation: "Der Beleihungswert ist der Wert, den eine Bank bei der Kreditvergabe als Sicherheit ansetzt. Er wird vorsichtig und nachhaltig ermittelt und liegt meist 10-20% unter dem Verkehrswert. Die Bank finanziert in der Regel nur einen Prozentsatz des Beleihungswerts (Beleihungsgrenze).", category: "Finanzierung", difficulty: "medium" },
  { id: "m5-q8", moduleId: 5, question: "Was bedeutet 'Sondertilgung'?", options: ["Eine besonders hohe Tilgung", "Eine außerplanmäßige Tilgung zusätzlich zur regulären Rate", "Eine Tilgung nur für Sonderfälle", "Eine Tilgung ohne Zinsen"], correctAnswer: 1, explanation: "Eine Sondertilgung ist eine außerplanmäßige Tilgung zusätzlich zur regulären monatlichen Rate. Sie ermöglicht es, das Darlehen schneller zurückzuzahlen. Sondertilgungen müssen im Darlehensvertrag vereinbart werden und sind oft auf einen bestimmten Prozentsatz pro Jahr begrenzt (z.B. 5%).", category: "Finanzierung", difficulty: "medium" },
  { id: "m5-q9", moduleId: 5, question: "Was ist eine 'Anschlussfinanzierung'?", options: ["Die erste Finanzierung einer Immobilie", "Die Finanzierung nach Ablauf der Zinsbindung", "Eine zusätzliche Finanzierung", "Eine Finanzierung für Anschlüsse (Wasser, Strom)"], correctAnswer: 1, explanation: "Eine Anschlussfinanzierung ist die Fortsetzung der Finanzierung nach Ablauf der Zinsbindung. Da das Darlehen meist noch nicht vollständig getilgt ist, muss eine neue Vereinbarung mit der Bank getroffen werden. Alternativ kann man zu einer anderen Bank wechseln (Umschuldung).", category: "Finanzierung", difficulty: "medium" },
  { id: "m5-q10", moduleId: 5, question: "Welche IHK-Prüfung ist für Immobilienmakler relevant?", options: ["Sachkundeprüfung nach § 34c GewO", "Meisterprüfung", "Gesellenprüfung", "Abitur"], correctAnswer: 0, explanation: "Die Sachkundeprüfung nach § 34c GewO ist für Immobilienmakler, Darlehensvermittler, Bauträger und Baubetreuer relevant. Sie wird von der IHK abgenommen und ist Voraussetzung für die Erlaubniserteilung. Die Prüfung umfasst rechtliche, wirtschaftliche und fachliche Kenntnisse.", category: "Prüfung", difficulty: "easy" },
  { id: "m5-extra-11", moduleId: 5, question: "Was versteht man unter dem Begriff 'Beleihungswert'?", options: ["Den aktuellen Marktwert einer Immobilie", "Den Wert, den die Bank langfristig als sicher erzielbar ansieht", "Den Kaufpreis der Immobilie", "Den steuerlichen Einheitswert"], correctAnswer: 1, explanation: "Der Beleihungswert ist ein Sicherheitswert, der langfristig und unabhängig von konjunkturellen Schwankungen erzielt werden kann. Er bildet die Basis für die Kreditentscheidung.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m5-extra-12", moduleId: 5, question: "Was ist ein Annuitätendarlehen?", options: ["Ein Darlehen, das am Ende der Laufzeit in einer Summe zurückgezahlt wird", "Ein Darlehen mit gleichbleibenden Raten aus Zins und Tilgung", "Ein Darlehen mit variablen Zinsen", "Ein staatlich gefördertes Darlehen"], correctAnswer: 1, explanation: "Beim Annuitätendarlehen bleibt die monatliche Rate (Annuität) über die Zinsbindungsfrist konstant. Da der Zinsanteil mit jeder Rate sinkt, steigt der Tilgungsanteil entsprechend an.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m5-extra-13", moduleId: 5, question: "Welche Unterlage ist für die Bonitätsprüfung eines Selbstständigen unerlässlich?", options: ["Die letzten drei Gehaltsabrechnungen", "Betriebswirtschaftliche Auswertungen (BWA) und Jahresabschlüsse", "Ein Arbeitsvertrag", "Eine Schufa-Selbstauskunft"], correctAnswer: 1, explanation: "Da Selbstständige kein festes Gehalt beziehen, prüft die Bank die wirtschaftliche Stabilität anhand von BWAs, Einnahmen-Überschuss-Rechnungen oder Bilanzen der letzten Jahre.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m5-extra-14", moduleId: 5, question: "Was bedeutet 'Vorfälligkeitsentschädigung'?", options: ["Eine Gebühr für die vorzeitige Auszahlung des Darlehens", "Eine Entschädigung der Bank für entgangene Zinsen bei vorzeitiger Rückzahlung", "Eine Prämie für pünktliche Ratenzahlung", "Die Kosten für die Eintragung der Grundschuld"], correctAnswer: 1, explanation: "Kündigt ein Darlehensnehmer den Kredit während der Zinsbindungsfrist, entsteht der Bank ein Zinsausfallschaden. Diesen muss der Kunde durch die Vorfälligkeitsentschädigung ausgleichen.", category: "Fachkenntnisse", difficulty: "medium" },
  { id: "m5-extra-15", moduleId: 5, question: "Welche Funktion hat das Grundbuch bei der Finanzierung?", options: ["Es dokumentiert den Zustand der Immobilie", "Es dient der Absicherung des Darlehens durch Eintragung einer Grundschuld", "Es regelt die Höhe der Grunderwerbsteuer", "Es enthält den Energieausweis"], correctAnswer: 1, explanation: "Das Grundbuch sichert das Darlehen dinglich ab. Die Bank lässt sich in Abteilung III eine Grundschuld oder Hypothek eintragen, um im Falle der Zahlungsunfähigkeit auf die Immobilie zugreifen zu können.", category: "Fachkenntnisse", difficulty: "medium" },
];

export function getQuestionsByModule(moduleId: number): UnifiedQuestion[] { return ALL_QUESTIONS.filter(q => q.moduleId === moduleId); }
export function shuffleQuestions<T>(arr: T[]): T[] { const a=[...arr]; for(let i=a.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]];} return a; }